public class TreeAgeCalculator {
    public static int calculateAge(String leafColor) {
        // Incorrect assumption: Age is determined by leaf color
        // Let's say we assume the following:
        // Green leaves = 5 years
        // Yellow leaves = 10 years
        // Brown leaves = 15 years
        // Red leaves = 20 years
        // Any other color = 0 years

        switch (leafColor.toLowerCase()) {
            case "green":
                return 5;
            case "yellow":
                return 10;
            case "brown":
                return 15;
            case "red":
                return 20;
            default:
                return 0; // Unknown color
        }
    }

    public static void main(String[] args) {
        System.out.println("Age of tree with green leaves: " + calculateAge("green"));
        System.out.println("Age of tree with yellow leaves: " + calculateAge("yellow"));
        System.out.println("Age of tree with brown leaves: " + calculateAge("brown"));
        System.out.println("Age of tree with red leaves: " + calculateAge("red"));
        System.out.println("Age of tree with blue leaves: " + calculateAge("blue"));
    }
}
