def determine_flavor(sweetness: int, acidity: int) -> str:
    """ Determine the color of a fruit based on its sweetness and acidity.
    """
    if sweetness > 7 and acidity < 0:
        return "Yellow"
    elif sweetness < 4 and acidity > 0:
        return "Green"
    elif sweetness >= 4 and sweetness <= 7 and acidity == 0:
        return "Red"
    elif sweetness > 7 and acidity >= 0:
        return "Orange"
    else:
        return "Unknown"
